import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
// Importamos el hook que acabamos de crear
import { useDebounce } from '../hooks/useDebounce'; 
// Usamos iconos de Font Awesome (que importamos en index.html)

const SearchBox = () => {
  const navigate = useNavigate();
  const location = useLocation();
  
  // Obtener el 'keyword' de la URL para mantener la sincronización inicial
  const queryParams = new URLSearchParams(location.search);
  const urlKeyword = queryParams.get('keyword') || '';

  // Estado local para el valor del input (cambia en cada pulsación)
  const [keyword, setKeyword] = useState(urlKeyword);
  
  // Valor "debounceado" (solo cambia después de 500ms de inactividad)
  const debouncedKeyword = useDebounce(keyword, 500);

  // Estado derivado para saber si estamos esperando a que termine el debounce.
  const isSearching = keyword !== urlKeyword && keyword !== debouncedKeyword;

  // EFECTO 1: Sincronizar el input si la URL cambia desde fuera (ej: clic en logo)
  useEffect(() => {
    if (keyword !== urlKeyword) {
      setKeyword(urlKeyword);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [urlKeyword]);

  // EFECTO 2: Realizar la búsqueda cuando el valor "debounceado" cambia
  useEffect(() => {
    if (debouncedKeyword === urlKeyword) {
      return;
    }

    const newParams = new URLSearchParams(location.search);

    if (debouncedKeyword.trim()) {
      // Si hay un término de búsqueda, lo añadimos y reseteamos la página
      newParams.set('keyword', debouncedKeyword.trim());
      newParams.set('page', '1');
      navigate(`/?${newParams.toString()}`);
    } else {
      // Si el campo de búsqueda se vacía, eliminamos el keyword y la página
      newParams.delete('keyword');
      newParams.delete('page');
      const newSearch = newParams.toString();
      navigate(newSearch ? `/?${newSearch}` : '/'); // Navega a '/' si no hay otros params
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [debouncedKeyword, navigate, location.search]);

  // Prevenir el envío tradicional del formulario
  const submitHandler = (e) => {
    e.preventDefault();
    // Si la búsqueda es manual, forzamos el debounce actual como keyword
    navigate(`/?keyword=${keyword.trim()}&page=1`);
  };

  const handleClearSearch = () => {
    setKeyword('');
    // Al limpiar localmente, el efecto de debounce se encargará de limpiar la URL
  };

  return (
    // CRÍTICO: Altura fija (h-10) y contenedor flex alineado al centro
    <form onSubmit={submitHandler} className="relative flex items-center w-full h-10" role="search">
      {/* Ícono de búsqueda posicionado a la izquierda */}
      <i className="fas fa-search absolute left-3 text-gray-400"></i>
      <input
        type="text"
        name="q"
        onChange={(e) => setKeyword(e.target.value)}
        value={keyword}
        placeholder="Buscar productos..."
        // Diseño de la barra: redondeada, fondo blanco, foco verde neón
        className="w-full h-10 py-0 pl-10 pr-10 rounded-lg border border-none shadow-sm 
          bg-white text-gray-900 placeholder-gray-500 focus:outline-none focus:ring-2 
          focus:ring-['var(--cta-color)'] focus:border-transparent transition-all duration-200"
        style={{ '--tw-ring-color': 'var(--cta-color)' }} // Inyectar variable CSS para el ring
        aria-label="Buscar productos"
      />
      {isSearching ? (
        // Spinner si está debouncing
        <div className="absolute right-3 flex items-center justify-center">
          <i className="fas fa-spinner fa-spin" style={{ color: 'var(--cta-color)' }}></i>
        </div>
      ) : keyword && (
        // Botón de limpiar si hay texto y no está buscando
        <button
          type="button"
          className="absolute right-3 text-gray-500 hover:text-gray-700 focus:outline-none"
          onClick={handleClearSearch}
          aria-label="Limpiar búsqueda"
        >
          <i className="fas fa-times"></i>
        </button>
      )}
    </form>
  );
};

export default SearchBox;
